29→
30→  // Main Constructor
31→  Potential(PotType a_ptype, const Parameters &a_params)
32→      : ptype{a_ptype},
33→        m_params{a_params},
34→        forceCallCounter{0} {
35→    initializeLogger();
36→  }
37→
38→  // Delegating Constructor
39→  Potential(const Parameters &a_params)
40→      : Potential(a_params.potential_options.potential, a_params) {}
41→
42→  virtual ~Potential() {
43→    if (m_log) {
44→      m_log->trace("[{}] destroyed after {} calls",
45→                   magic_enum::enum_name<PotType>(getType()), forceCallCounter);
46→    } else {
47→      std::cerr << "Logger is not initialized\n";
48→    }
49→  }
50→
51→  static int fcalls;
52→  static int fcallsTotal;
53→  static int wu_fcallsTotal;
54→  static double totalUserTime;
55→
56→  // Does not take into account the fixed / free atoms
57→  // Variance here is null when not needed and that's OK
58→  void virtual force(long nAtoms, const double *positions, const int *atomicNrs,
59→                     double *forces, double *energy, double *variance,
60→                     const double *box) = 0;
61→
62→  std::tuple<double, AtomMatrix>
63→  get_ef(const AtomMatrix &pos, const VectorXi &atmnrs, const Matrix3d &box);
64→
65→  PotType getType() { return this->ptype; }
66→
67→  // Logger initialization
68→  void initializeLogger() {
69→    if (!spdlog::get("_potcalls")) {
70→      // Create logger if it doesn't exist
71→      m_log = spdlog::basic_logger_mt("_potcalls", "_potcalls.log", true);
72→      m_log->set_pattern("[%l] [%Y-%m-%d %H:%M:%S] %v");
73→    } else {
74→      // Use existing logger
75→      m_log = spdlog::get("_potcalls");
76→    }
77→    if (m_log) {
78→      m_log->trace("[{}] created", magic_enum::enum_name<PotType>(getType()));
79→    }
80→  }
81→};
